mapper.update:
UPDATE `draft`
SET title = #{title},
    content = #{content},
    status = #{status},
    version = #{version},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND version = #{expectedVersion}

mapper.delete:
DELETE FROM `draft`
WHERE id = #{id}
  AND version = #{expectedVersion}

mapper.select:
SELECT id, author_id, title, content, status, version, created_at, updated_at
FROM `draft`
WHERE id = #{id}

SELECT id, author_id, title, content, status, version, created_at, updated_at
FROM `draft`
WHERE author_id = #{authorId}

    AND status = #{status}

ORDER BY updated_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM `draft`
WHERE author_id = #{authorId}

    AND status = #{status}
